module edge_detect
(
    input clk,
    input rst_n,
    input a,
    output reg rise,
    output reg down
);
    // ADD CODE BELOW
    // Declare edge_detect module variables
    reg[1:0] state;
    reg[1:0] next_state;
    wire a_posedge, a_negedge;
    // Declare internal wires
    // Define state transition logic
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state <= 2'b00;
        end else begin
            state <= next_state;
        end
    end
    // ADD CODE BELOW
    // Define output logic
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            rise <= 1'b0;
            down <= 1'b0;
        end else begin
            if (a_posedge) begin
                rise <= 1'b1;
                down <= 1'b0;
            end else if (a_negedge) begin
                rise <= 1'b0;
                down <= 1'b1;
            end else begin
                rise <= 1'b0;
                down <= 1'b0;
            end
        end
    end
    // ADD CODE BELOW
    // Define next state logic
    always @(*) begin
        if (state == 2'b00) begin
            if (a) begin
                next_state = 2'b01;
            end else begin
                next_state = 2'b00;
            end
        end else if (state == 2'b01) begin
            if (a) begin
                next_state = 2'b01;
            end else begin
                next_state = 2'b10;
            end
        end else if (state == 2'b10) begin
            if (a) begin
                next_state = 2'b11;
            end else begin
                next_state = 2'b10;
            end
        end else if (state == 2'b11) begin
            if (a) begin
                next_state = 2'b11;
            end else begin
                next_state = 2'b00;
            end
        end
    end
    // ADD CODE BELOW
    // Define edge detection logic
    assign a_posedge = 0;
    assign a_negedge = 0;
    always @(*) begin
        if (state == 2'b00) begin
            if (a) begin
                a_posedge = 1'b1;
                a_negedge = 1'b0;
            end else begin
                a_posedge = 1'b0;
                a_negedge = 1'b0;
            end
        end else if (state == 2'b01) begin
            if (a) begin
                a_posedge = 1'b0;
                a_negedge = 1'b0;
            end else begin
                a_posedge = 1'b0;
                a_negedge = 1'b1;
            end
        end else if (state == 2'b10) begin
            if (a) begin
                a_posedge = 1'b0;
                a_negedge = 1'b0;
            end else begin
                a_posedge = 1'b1;
                a_negedge = 1'b0;
            end
        end else if (state == 2'b11) begin
            if (a) begin
                a_posedge = 1'b0;
                a_negedge = 1'b0;
            end else begin
                a_posedge = 1'b0;
                a_negedge = 1'b0;
            end
        end
    end
endmodule
